typedef struct latLong
{
  float lat;
  float lng;
} LatLong;

typedef struct record
{
  char recString[REC_LENGTH];
  float distance;
} Record;

typedef struct RecordVector {
    Record *data;
    int size;
    int capacity;
} RecordVector;

typedef struct LatLongVector {
    LatLong *data;
    int size;
    int capacity;
} LatLongVector;

void RecordVector_init(RecordVector *vec) {
    vec->size = 0;
    vec->capacity = 1024;
    vec->data = (Record*)malloc(sizeof(Record)*vec->capacity);
    if (!vec->data) {
        fprintf(stderr, "Failed to allocate RecordVector\n");
        exit(1);
    }
}

void RecordVector_push_back(RecordVector *vec, Record *rec) {
    if (vec->size >= vec->capacity) {
        vec->capacity *= 2;
        vec->data = (Record*)realloc(vec->data, sizeof(Record)*vec->capacity);
        if (!vec->data) {
            fprintf(stderr, "Failed to reallocate RecordVector\n");
            exit(1);
        }
    }
    vec->data[vec->size++] = *rec;
}

void RecordVector_free(RecordVector *vec) {
    free(vec->data);
    vec->data = NULL;
    vec->size = 0;
    vec->capacity = 0;
}

void LatLongVector_init(LatLongVector *vec) {
    vec->size = 0;
    vec->capacity = 1024;
    vec->data = (LatLong*)malloc(sizeof(LatLong)*vec->capacity);
    if (!vec->data) {
        fprintf(stderr, "Failed to allocate LatLongVector\n");
        exit(1);
    }
}

void LatLongVector_push_back(LatLongVector *vec, LatLong *loc) {
    if (vec->size >= vec->capacity) {
        vec->capacity *= 2;
        vec->data = (LatLong*)realloc(vec->data, sizeof(LatLong)*vec->capacity);
        if (!vec->data) {
            fprintf(stderr, "Failed to reallocate LatLongVector\n");
