void euclid(LatLong *locations, float *distances, int numRecords,float lat, float lng)
{
    int i;
    #pragma omp parallel for schedule(static)
    for(i=0; i<numRecords; i++) {
        LatLong *latLong = locations + i;
        float *dist = distances + i;
        *dist = (float)sqrt((lat - latLong->lat)*(lat - latLong->lat) + (lng - latLong->lng)*(lng - latLong->lng));
    }
}

int main(int argc, char* argv[])
{
	int    i=0;
	float lat=0.0f, lng=0.0f;
	int quiet=0,timing=0,platform=0,device=0;

    RecordVector records;
	LatLongVector locations;
	char filename[100];
	int resultsCount=10;

    RecordVector_init(&records);
    LatLongVector_init(&locations);

    if (parseCommandline(argc, argv, filename,&resultsCount,&lat,&lng,
                     &quiet, &timing, &platform, &device)) {
      printUsage();
      return 0;
    }

    int numRecords = loadData(filename,&records,&locations);
    if (resultsCount > numRecords) resultsCount = numRecords;

	float *distances = (float *)malloc(sizeof(float) * numRecords);
	if (!distances) {
		fprintf(stderr, "Failed to allocate distances array\n");
        RecordVector_free(&records);
        LatLongVector_free(&locations);
		return 1;
	}

#ifdef TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif

    euclid(locations.data, distances, numRecords, lat, lng);

#ifdef TIMING
    gettimeofday(&tv_kernel_end, NULL);
    tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    findLowest(&records,distances,numRecords,resultsCount);

    if (!quiet)
    for(i=0;i<resultsCount;i++) {
      printf("%s --> Distance=%f\n",records.data[i].recString,records.data[i].distance);
    }
    free(distances);
    RecordVector_free(&records);
    LatLongVector_free(&locations);

#ifdef  TIMING
    printf("Exec: %f\n", kernel_time);
#endif
    return 0;
}

int loadData(char *filename, RecordVector *records, LatLongVector *locations){
    FILE   *flist,*fp;
	int    i=0;
	char dbname[64];
	int recNum=0;

    flist = fopen(filename, "r");
	if (!flist) {
		fprintf(stderr, "Error opening file list %s\n", filename);
		exit(1);
	}
	while(!feof(flist)) {
		if(fscanf(flist, "%s\n", dbname) != 1) {
            fprintf(stderr, "error reading filelist\n");
            exit(0);
        }
        fp = fopen(dbname, "r");
        if(!fp) {
            printf("error opening a db\n");
            exit(1);
        }

        while(!feof(fp)){
            Record record;
            LatLong latLong;
            if (!fgets(record.recString,49,fp)) break;
            fgetc(fp); 
            if (feof(fp)) break;

            char substr[6];

            for(i=0;i<5;i++) substr[i] = *(record.recString+i+28);
            substr[5] = '\0';
            latLong.lat = atof(substr);

            for(i=0;i<5;i++) substr[i] = *(record.recString+i+33);
            substr[5] = '\0';
            latLong.lng = atof(substr);

            LatLongVector_push_back(locations, &latLong);
            RecordVector_push_back(records, &record);
            recNum++;
        }
        fclose(fp);
    }
    fclose(flist);

    return recNum;
}

void findLowest(RecordVector *records,float *distances,int numRecords,int topN){
  int i,j;
  float val;
  int minLoc;
  Record tempRec;
  float tempDist;

  for(i=0;i<topN;i++) {
    minLoc = i;
    for(j=i;j<numRecords;j++) {
      val = distances[j];
      if (val < distances[minLoc]) minLoc = j;
    }

    tempRec = records->data[i];
    records->data[i] = records->data[minLoc];
    records->data[minLoc] = tempRec;

    tempDist = distances[i];
    distances[i] = distances[minLoc];
    distances[minLoc] = tempDist;

    records->data[i].distance = distances[i];
  }
}

int parseCommandline(int argc, char *argv[], char* filename,int *r,float *lat,float *lng,
                     int *q, int *t, int *p, int *d){
    int i;
    if (argc < 2) return 1; 
    strncpy(filename,argv[1],100);
    char flag;

    for(i=1;i<argc;i++) {
      if (argv[i][0]=='-') {
        flag = argv[i][1];
          switch (flag) {
            case 'r': 
              i++;
              *r = atoi(argv[i]);
              break;
            case 'l': 
              if (argv[i][2]=='a') {
                *lat = atof(argv[i+1]);
              }
              else {
                *lng = atof(argv[i+1]);
              }
              i++;
              break;
            case 'h': 
              return 1;
            case 'q': 
              *q = 1;
              break;
            case 't': 
              *t = 1;
              break;
            case 'p': 
              i++;
              *p = atoi(argv[i]);
              break;
            case 'd': 
              i++;
              *d = atoi(argv[i]);
              break;
        }
      }
    }
    if ((*d >= 0 && *p<0) || (*p>=0 && *d<0)) 
      return 1;
    return 0;
}

